        $this->assertEquals($val->getValue(), $back->getValue());
        $val = new XdrAssetType(XdrAssetType::ASSET_TYPE_CREDIT_ALPHANUM4);
        $name = $val->enumName();
        $this->assertEquals('ASSET_TYPE_CREDIT_ALPHANUM4', $name);
